import React, { useState, useEffect } from 'react';

const STARS = Array.from({ length: 60 }, (_, i) => ({
  id: i, top: Math.random() * 100, left: Math.random() * 100,
  size: Math.random() * 2 + 0.5, duration: Math.random() * 3 + 2, delay: Math.random() * 4,
}));

function Landing() {
  const [owlBlink, setOwlBlink] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const blink = setInterval(() => {
      setOwlBlink(true);
      setTimeout(() => setOwlBlink(false), 150);
    }, 3000);
    const scroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', scroll);
    return () => { clearInterval(blink); window.removeEventListener('scroll', scroll); };
  }, []);

  return (
    <div style={s.page}>

      {/* Stars */}
      <div style={s.stars}>
        {STARS.map(star => (
          <div key={star.id} style={{
            position:'absolute', top:`${star.top}%`, left:`${star.left}%`,
            width:`${star.size}px`, height:`${star.size}px`,
            background:'#ffffff', borderRadius:'50%', opacity:0,
            animation:`twinkle ${star.duration}s ease-in-out infinite`,
            animationDelay:`${star.delay}s`,
          }}/>
        ))}
      </div>

      {/* Glow blobs */}
      <div style={{ position:'fixed', top:'-200px', left:'-100px', width:'600px', height:'600px', background:'radial-gradient(circle, rgba(34,197,94,0.06) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }}/>
      <div style={{ position:'fixed', bottom:'-200px', right:'0', width:'500px', height:'500px', background:'radial-gradient(circle, rgba(99,102,241,0.05) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }}/>

      {/* Navbar */}
      <nav style={{ ...s.nav, background: scrolled ? 'rgba(8,8,8,0.95)' : 'transparent', borderBottom: scrolled ? '1px solid #1a1a1a' : 'none' }}>
        <div style={s.navLogo}>
          <span style={{ fontSize:'24px' }}>🦉</span>
          <span style={s.navLogoText}>Dev<span style={{ color:'#22c55e' }}>Nest</span></span>
        </div>
        <div style={s.navLinks}>
          {['DSA Tracker', 'GitHub Analytics', 'AI Mentor', 'Portfolio'].map(link => (
            <span key={link} style={s.navLink}>{link}</span>
          ))}
        </div>
        <div style={s.navRight}>
          <a href="/login" style={s.navLoginBtn}>Login / Signup →</a>
        </div>
      </nav>

      {/* Hero Section */}
      <div style={s.hero}>

        {/* Headline */}
        <div style={s.heroText}>
          <h1 style={s.headline}>Track, analyze & share</h1>
          <p style={s.subheadline}>
            <strong style={{ color:'#ffffff' }}>Dev<span style={{ color:'#22c55e' }}>Nest</span></strong>
            {' '}helps you navigate and track your{' '}
            <br/>coding journey to success
          </p>

          <div style={s.ctaRow}>
            <a href="/dashboard" style={s.ctaSecondary}>DSA Tracker</a>
            <a href="/register" style={s.ctaPrimary}>Get Started →</a>
          </div>

          {/* Stats */}
          <div style={s.statsRow}>
            {[
              { num: '25+',  label: 'DSA Problems'    },
              { num: 'AI',   label: 'Powered Mentor'  },
              { num: '100%', label: 'Free to Use'     },
              { num: '1',    label: 'Platform'        },
            ].map(stat => (
              <div key={stat.label} style={s.statItem}>
                <div style={s.statNum}>{stat.num}</div>
                <div style={s.statLabel}>{stat.label}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Owl + Dashboard Preview */}
        <div style={s.heroVisual}>

          {/* Animated Owl */}
          <div style={s.owlContainer}>
            <svg width="160" height="185" viewBox="0 0 160 185" style={{ animation:'owlFloat 3.5s ease-in-out infinite', filter:'drop-shadow(0 20px 40px rgba(34,197,94,0.15))' }}>
              {/* Body */}
              <ellipse cx="80" cy="140" rx="42" ry="48" fill="#1a2810"/>
              <ellipse cx="80" cy="150" rx="28" ry="32" fill="#e8d5a0"/>
              {/* Body stripes */}
              <path d="M65,140 Q80,143 95,140" stroke="#c8b078" strokeWidth="1.2" fill="none" opacity=".5"/>
              <path d="M62,152 Q80,155 98,152" stroke="#c8b078" strokeWidth="1" fill="none" opacity=".4"/>
              <path d="M65,163 Q80,166 95,163" stroke="#c8b078" strokeWidth=".8" fill="none" opacity=".3"/>
              {/* Wings */}
              <path d="M38,125 Q10,100 14,142 Q28,162 56,152Z" fill="#162410"/>
              <path d="M122,125 Q150,100 146,142 Q132,162 104,152Z" fill="#162410"/>
              <path d="M38,125 Q14,104 18,138 Q30,154 54,146Z" fill="#1e3018"/>
              <path d="M122,125 Q146,104 142,138 Q130,154 106,146Z" fill="#1e3018"/>
              {/* Head */}
              <circle cx="80" cy="72" r="48" fill="#1a2810"/>
              {/* Ear tufts */}
              <polygon points="54,38 44,10 66,32" fill="#162410"/>
              <polygon points="106,38 116,10 94,32" fill="#162410"/>
              <polygon points="54,36 48,14 64,30" fill="#243d1c"/>
              <polygon points="106,36 112,14 96,30" fill="#243d1c"/>
              {/* Graduation cap */}
              <rect x="36" y="28" width="88" height="8" rx="2" fill="#8B0000" opacity=".9"/>
              <polygon points="80,10 36,30 80,36 124,30" fill="#A00000"/>
              <rect x="76" y="10" width="8" height="4" fill="#A00000"/>
              <line x1="124" y1="30" x2="134" y2="44" stroke="#FFD700" strokeWidth="2"/>
              <circle cx="134" cy="47" r="4" fill="#FFD700"/>
              {/* Glasses frames */}
              <circle cx="62" cy="70" r="18" fill="none" stroke="#8B6914" strokeWidth="2.5" opacity=".8"/>
              <circle cx="98" cy="70" r="18" fill="none" stroke="#8B6914" strokeWidth="2.5" opacity=".8"/>
              <line x1="80" y1="70" x2="80" y2="70" stroke="#8B6914" strokeWidth="2.5"/>
              <path d="M80,70 L80,70" stroke="#8B6914" strokeWidth="2.5"/>
              <path d="M62,52 Q55,48 48,52" stroke="#8B6914" strokeWidth="2" fill="none" opacity=".7"/>
              <path d="M98,52 Q105,48 112,52" stroke="#8B6914" strokeWidth="2" fill="none" opacity=".7"/>
              {/* Eyes */}
              <circle cx="62" cy="70" r="14" fill="#f0e4c0"/>
              <circle cx="62" cy="70" r="10" fill="#f59e0b"/>
              <circle cx="62" cy="70" r="6" fill="#111"/>
              <circle cx="65" cy="67" r="2.5" fill="white" opacity=".9"/>
              <circle cx="64" cy="69" r="1" fill="white" opacity=".5"/>
              {owlBlink && <rect x="44" y="57" width="36" height="26" rx="13" fill="#1a2810"/>}
              <circle cx="98" cy="70" r="14" fill="#f0e4c0"/>
              <circle cx="98" cy="70" r="10" fill="#f59e0b"/>
              <circle cx="98" cy="70" r="6" fill="#111"/>
              <circle cx="101" cy="67" r="2.5" fill="white" opacity=".9"/>
              <circle cx="100" cy="69" r="1" fill="white" opacity=".5"/>
              {owlBlink && <rect x="80" y="57" width="36" height="26" rx="13" fill="#1a2810"/>}
              {/* Beak */}
              <polygon points="80,84 70,100 90,100" fill="#e07820"/>
              <line x1="80" y1="84" x2="80" y2="100" stroke="#b85c14" strokeWidth="1"/>
              {/* Feet */}
              <rect x="50" y="178" width="24" height="7" rx="3.5" fill="#4a2e1a"/>
              <path d="M54,178 L48,185 M58,178 L57,185 M62,178 L67,185" stroke="#2d4a20" strokeWidth="2.5" strokeLinecap="round" fill="none"/>
              <rect x="86" y="178" width="24" height="7" rx="3.5" fill="#4a2e1a"/>
              <path d="M90,178 L84,185 M94,178 L93,185 M98,178 L103,185" stroke="#2d4a20" strokeWidth="2.5" strokeLinecap="round" fill="none"/>
              {/* Perch */}
              <rect x="30" y="183" width="100" height="8" rx="4" fill="#3d2810"/>
            </svg>
          </div>

          {/* Dashboard Preview Card */}
          <div style={s.dashPreview}>
            {/* Profile mini */}
            <div style={s.previewProfile}>
              <div style={s.previewAvatar}>S</div>
              <div>
                <div style={s.previewName}>Shrey Jain</div>
                <div style={s.previewHandle}>@shreyjain</div>
              </div>
            </div>

            {/* Stats */}
            <div style={s.previewStats}>
              <div style={s.previewStat}>
                <div style={{ fontSize:'28px', fontWeight:'700', color:'#ffffff' }}>25</div>
                <div style={{ fontSize:'10px', color:'#6b7280' }}>Problems Solved</div>
              </div>
              <div style={s.previewStat}>
                <div style={{ fontSize:'28px', fontWeight:'700', color:'#ffffff' }}>12</div>
                <div style={{ fontSize:'10px', color:'#6b7280' }}>Repos</div>
              </div>
              <div style={s.previewStat}>
                <div style={{ fontSize:'28px', fontWeight:'700', color:'#22c55e' }}>78%</div>
                <div style={{ fontSize:'10px', color:'#6b7280' }}>AI Readiness</div>
              </div>
            </div>

            {/* Progress rings */}
            <div style={s.previewRings}>
              {[
                { label:'Easy',   val:80, color:'#22c55e' },
                { label:'Medium', val:45, color:'#f59e0b' },
                { label:'Hard',   val:20, color:'#ef4444'  },
              ].map(ring => (
                <div key={ring.label} style={s.ringItem}>
                  <svg width="56" height="56" viewBox="0 0 56 56">
                    <circle cx="28" cy="28" r="22" fill="none" stroke="#1a1a1a" strokeWidth="4"/>
                    <circle cx="28" cy="28" r="22" fill="none" stroke={ring.color} strokeWidth="4"
                      strokeDasharray={`${ring.val * 1.38} 138`}
                      strokeLinecap="round"
                      transform="rotate(-90 28 28)"
                    />
                    <text x="28" y="33" textAnchor="middle" fill={ring.color} fontSize="10" fontWeight="700" fontFamily="Poppins">{ring.val}%</text>
                  </svg>
                  <div style={{ fontSize:'10px', color:'#6b7280', marginTop:'4px' }}>{ring.label}</div>
                </div>
              ))}
            </div>

            {/* Heatmap mini */}
            <div style={s.heatmapRow}>
              {Array.from({ length: 28 }, (_, i) => (
                <div key={i} style={{
                  width:'10px', height:'10px', borderRadius:'2px',
                  background: Math.random() > 0.5 ? `rgba(34,197,94,${Math.random() * 0.8 + 0.2})` : '#1a1a1a',
                }}/>
              ))}
            </div>
          </div>

          {/* Codolio Card style - floating */}
          <div style={s.floatingCard}>
            <div style={{ fontSize:'10px', color:'#22c55e', fontWeight:'600', marginBottom:'8px' }}>DevNest CARD</div>
            <div style={{ width:'48px', height:'48px', borderRadius:'50%', background:'linear-gradient(135deg, #22c55e, #16a34a)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'20px', fontWeight:'700', color:'#000', margin:'0 auto 8px' }}>S</div>
            <div style={{ fontSize:'13px', fontWeight:'600', color:'#fff', textAlign:'center' }}>Shrey Jain ✅</div>
            <div style={{ fontSize:'10px', color:'#6b7280', textAlign:'center', marginBottom:'10px' }}>@shreyjain</div>
            <div style={{ display:'flex', gap:'8px', justifyContent:'center' }}>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:'16px', fontWeight:'700', color:'#fff' }}>25</div>
                <div style={{ fontSize:'9px', color:'#6b7280' }}>Questions</div>
              </div>
              <div style={{ width:'1px', background:'#2a2a2a' }}/>
              <div style={{ textAlign:'center' }}>
                <div style={{ fontSize:'16px', fontWeight:'700', color:'#22c55e' }}>7</div>
                <div style={{ fontSize:'9px', color:'#6b7280' }}>Streak</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes twinkle {
          0%,100%{opacity:0;transform:scale(0.5)}
          50%{opacity:0.6;transform:scale(1)}
        }
        @keyframes owlFloat {
          0%,100%{transform:translateY(0px) rotate(-1deg)}
          50%{transform:translateY(-14px) rotate(1deg)}
        }
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
}

